var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"꺄아악!!","JPN":"きゃああっ！？","ENG":"Eeeek!","TWN":"啊啊！！"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이런, 다친 데는 없니?","JPN":"あら、怪我はない？","ENG":"Oh dear, are you alright?","TWN":"哎呀，沒受傷吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"정신 단단히 차리렴. 마법을 배우고 마녀가 되는 과정이란 게 그리 안전하지만은 않거든.","JPN":"しっかりしないとダメよ。魔法を学んで魔女になる過程は決して安全ではないわ。","ENG":"You'd better brace yourself. Learning magic and becoming a witch isn't all that safe.","TWN":"妳必須打起精神，學習魔法成為魔女的過程可不輕鬆。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"가, 감사합니다. 침식체를 직접 본 건 처음이라서요.","JPN":"あ、ありがとうございます！　目の前で侵食体を見たのは初めてで……","ENG":"Th-thank you. It's just that I've never seen Corrupted Objects in real life before.","TWN":"謝、謝謝。但因為這是我第一次親眼看到侵蝕體。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하긴, 누구든 저런 걸 갑자기 마주치면 당황하기 마련이지.","JPN":"確かにあんなものにいきなり出くわしたら、誰だって慌てるでしょうね。","ENG":"I guess anyone would be startled if they ran into one of those things suddenly.","TWN":"也是，換作是誰第一次看到那個東西，都會很慌張。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭐야, 순 느림보들뿐이잖아? 더 강한 녀석은 없냐?","JPN":"なによ、全部のろまばかりじゃない！　もっと強いやつはいないの？","ENG":"Why do we only have slowpokes around here? Aren't there any stronger ones?","TWN":"在做什麼，慢死了！沒有更強一點的傢伙嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"가끔은 예외도 있긴 하지만.","JPN":"たまに例外もいるけど。","ENG":"Of course, there are always exceptions.","TWN":"有時也會有例外。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저어, 그런데 여긴 어디죠?","JPN":"あの、ところでここはどこですか？","ENG":"So... Where are we anyway?","TWN":"請問，這裡是哪裡？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"지하실 문을 열고 들어왔는데 어떻게 이런 넓은 공간이 있는 거예요?","JPN":"地下室の扉の奥に、どうしてこんな広い空間があるんですか？","ENG":"How is there such a large space down here? I thought I was walking into the basement.","TWN":"地下室門後怎麼會有這麼寬敞的空間呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"보고도 모르겠어? 여긴 이면세계야.","JPN":"見てわからないか？　ここは裏世界だ。","ENG":"Can't you tell? This is the Counterside.","TWN":"妳還沒看出來嗎？這裡是異界啊。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"침식체가 나타나고 현실이 아닌 공간이 그 외에 뭐가 있겠어.","JPN":"侵食体が現れる現実ではない空間といえば、そこしかないだろ。","ENG":"Why else would there be Corrupted Objects running free like this?","TWN":"出現侵蝕體的非現實空間，除了異界還能是哪裡。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이면세계는 차원 함선으로만 갈 수 있는 데 아니었어요?","JPN":"裏世界って次元艦船に乗らないと行けない所では？","ENG":"But I thought you needed one of those fancy ships to get to the Counterside.","TWN":"不是只有次元艦船才能去異界嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"수상한 카페 지하실 문이랑 이어져 있다는 얘기는 한 번도 못 들어봤다고요!","JPN":"怪しいカフェの地下室の扉から続いてるなんて話は聞いたことがないです！","ENG":"I never heard of anyone going there through a creepy door in a cafe!","TWN":"我還從沒聽說過異界是和可疑的咖啡店地下室連在一起的！"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"지금은 그게 일반적이긴 하지.","JPN":"今はその説が一般的ね。","ENG":"True, that's how it's usually done.","TWN":"現在的確是那樣。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하지만 생각해 봐. 차원 함선이 없던 시절에도 침식체들은 나타났어.","JPN":"でも考えてみて。次元艦船がなかった時代にも侵食体は現れてたわ。","ENG":"But think about it. We had C.O.s appear even before we had those ships.","TWN":"但妳想想，在沒有次元艦船的時代，也有侵蝕體啊。"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 그것들은 어디에서 왔을까?","JPN":"それらはどこから来たと思う？","ENG":"Where do you think they came from?","TWN":"那些侵蝕體是從哪裡來的呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};